// Portable request-time SSR handler used by emitted Vercel functions
// (edge / node / bun). No Bun-only APIs — renders with react-dom/server.
// The per-route entry (generated by the build) supplies the routing-file
// modules + assets and exports `{ fetch }` / default from makeRouteHandler().
import { createElement } from "react";

async function renderTree(tree) {
  try {
    const { renderToReadableStream } = await import("react-dom/server.edge");
    const stream = await renderToReadableStream(tree);
    if (stream.allReady) await stream.allReady;
    return await new Response(stream).text();
  } catch {
    const { renderToString } = await import("react-dom/server");
    return renderToString(tree);
  }
}

function parseCookies(request) {
  const header = request.headers.get("cookie") || "";
  const map = new Map();
  for (const part of header.split(";")) {
    const i = part.indexOf("=");
    if (i > 0) map.set(part.slice(0, i).trim(), decodeURIComponent(part.slice(i + 1).trim()));
  }
  return { get: (k) => map.get(k), has: (k) => map.has(k) };
}

function matchParams(pattern, pathname) {
  const segs = pathname.replace(/^\/+|\/+$/g, "").split("/").filter(Boolean);
  const params = {};
  for (let i = 0; i < pattern.length; i++) {
    const p = pattern[i];
    if (p.startsWith("[...") && p.endsWith("]")) {
      params[p.slice(4, -1)] = segs.slice(i);
      return params;
    }
    if (p.startsWith("[") && p.endsWith("]")) params[p.slice(1, -1)] = segs[i];
  }
  return params;
}

const pick = (mod, ...keys) => {
  for (const k of keys) if (mod && mod[k] != null) return mod[k];
  return undefined;
};
const matchesMatcher = (pathname, matcher) => {
  const list = Array.isArray(matcher) ? matcher : [matcher];
  return list.some((m) => {
    const re = new RegExp(`^${String(m).replace(/\*\*/g, ".*").replace(/(?<!\.)\*/g, "[^/]*")}$`);
    return re.test(pathname);
  });
};

function escAttr(s) {
  return String(s).replace(/&/g, "&amp;").replace(/"/g, "&quot;").replace(/</g, "&lt;");
}
function buildSeoHead(r) {
  if (!r || typeof r !== "object") return "";
  const out = [];
  if (r.title) out.push(`<title>${escAttr(r.title)}</title>`);
  if (r.description) out.push(`<meta name="description" content="${escAttr(r.description)}" />`);
  if (r.canonical) out.push(`<link rel="canonical" href="${escAttr(r.canonical)}" />`);
  if (r.robots) out.push(`<meta name="robots" content="${escAttr(r.robots)}" />`);
  for (const [k, v] of Object.entries(r.openGraph || {})) out.push(`<meta property="og:${escAttr(k)}" content="${escAttr(v)}" />`);
  const jsonLd = r.jsonLd ? (Array.isArray(r.jsonLd) ? r.jsonLd : [r.jsonLd]) : [];
  for (const ld of jsonLd) out.push(`<script type="application/ld+json">${JSON.stringify(ld).replace(/</g, "\\u003c")}</script>`);
  return out.join("\n");
}

// Returns a Response when a control (returned object or thrown digest) ends the
// request; null to continue.
function controlToResponse(c, url) {
  if (!c || typeof c !== "object") return null;
  if (c.kind === "redirect") {
    return new Response(null, { status: c.status || 307, headers: { Location: new URL(c.to, url).toString() } });
  }
  if (c.kind === "notFound") return new Response("Not Found", { status: 404 });
  if (c.kind === "response" && c.response) return c.response;
  return null;
}
function thrownToResponse(err, url) {
  if (err?.__response instanceof Response) return err.__response;
  const digest = err?.digest;
  if (digest && String(digest).startsWith("REDIRECT")) {
    const [, status, ...rest] = String(digest).split(";");
    return new Response(null, { status: Number(status) || 307, headers: { Location: new URL(rest.join(";"), url).toString() } });
  }
  if (digest === "NOT_FOUND" || err?.name === "NotFoundError") return new Response("Not Found", { status: 404 });
  if (digest === "FORBIDDEN" || err?.name === "ForbiddenError") return new Response("Forbidden", { status: 403 });
  if (digest === "UNAUTHORIZED" || err?.name === "UnauthorizedError") return new Response("Unauthorized", { status: 401 });
  return null;
}

export function makeRouteHandler(opts) {
  return async function fetch(request) {
    const url = new URL(request.url);
    const params = matchParams(opts.pattern || [], url.pathname);
    const setCookies = [];
    const localsMap = new Map();
    const ctx = {
      url,
      request,
      method: request.method,
      headers: request.headers,
      params,
      searchParams: Object.fromEntries(url.searchParams.entries()),
      cookies: parseCookies(request),
      locals: { get: (k) => localsMap.get(k), set: (k, v) => localsMap.set(k, v) },
      runtime: opts.runtime,
      __setCookies: setCookies,
    };

    try {
      // proxy.ts (outer → inner)
      for (const mod of opts.proxies || []) {
        const fn = pick(mod, "default", "proxy");
        if (typeof fn !== "function") continue;
        const matcher = mod.matcher;
        if (matcher && !matchesMatcher(url.pathname, matcher)) continue;
        const r = controlToResponse(await fn(ctx), url);
        if (r) return r;
      }

      // schema.ts — validate params + searchParams (400 on invalid params)
      const querySpec = pick(opts.query || {}, "query");
      for (const mod of opts.schemas || []) {
        if (mod.params?.safeParse) {
          const r = mod.params.safeParse(ctx.params);
          if (!r.success) {
            return Response.json({ error: "Invalid params", issues: r.error?.issues ?? r.error }, { status: 400 });
          }
          Object.assign(ctx.params, r.data);
        }
        const searchSchema = querySpec?.parse ?? mod.searchParams;
        if (searchSchema?.safeParse) {
          const r = searchSchema.safeParse(ctx.searchParams);
          if (r.success) Object.assign(ctx.searchParams, r.data);
        }
      }

      // guard.ts (only if enabled at build time)
      if (opts.guardEnabled) {
        for (const mod of opts.guards || []) {
          const fn = pick(mod, "default", "guard");
          if (typeof fn !== "function") continue;
          const r = controlToResponse(await fn(ctx), url);
          if (r) return r;
        }
      }

      // action.ts on mutating requests (leaf only)
      let actionData;
      if (ctx.method !== "GET" && ctx.method !== "HEAD" && opts.action) {
        const fn = pick(opts.action, "default", "action");
        if (typeof fn === "function") {
          const actx = Object.assign({}, ctx, {
            formData: () => request.formData(),
            json: () => request.json(),
          });
          const result = await fn(actx);
          const r = controlToResponse(result, url);
          if (r) return r;
          actionData = result;
        }
      }

      // loader.ts (parallel along the chain)
      const loaded = await Promise.all(
        (opts.loaders || []).map(async (mod) => {
          const fn = pick(mod, "default", "loader");
          return typeof fn === "function" ? fn(ctx) : undefined;
        }),
      );
      const loaderData = loaded.length ? loaded[loaded.length - 1] : undefined;

      // state.ts → window.__SR_STATE__
      let serverState;
      const stateFn = pick(opts.state || {}, "default", "state");
      if (typeof stateFn === "function") serverState = await stateFn(ctx);

      // seo.tsx (has loader data)
      let seoHead = "";
      const seoFn = pick(opts.seo || {}, "default", "seo");
      if (typeof seoFn === "function") {
        seoHead = buildSeoHead(await seoFn(Object.assign({}, ctx, { data: loaderData })));
      }

      const page = pick(opts.page, "default", "Page", "page");
      let tree = createElement(page, { params, loaderData });
      for (let i = (opts.layouts || []).length - 1; i >= 0; i--) {
        const Layout = pick(opts.layouts[i], "default", "Layout", "layout");
        if (Layout) tree = createElement(Layout, null, tree);
      }
      const body = await renderTree(tree);

      // seo.tsx output is authoritative — drop the captured <title> if it sets one.
      let baseHead = opts.head || "";
      if (/<title/i.test(seoHead)) baseHead = baseHead.replace(/<title>[\s\S]*?<\/title>/i, "");
      const head = `${baseHead}${seoHead}`;
      const stateScript =
        serverState !== undefined
          ? `<script>window.__SR_STATE__=${JSON.stringify(serverState).replace(/</g, "\\u003c")}</script>`
          : "";
      const html =
        `<!DOCTYPE html><html lang="en"><head>${head}</head>` +
        `<body>${body}${opts.bodyScripts || ""}${stateScript}</body></html>`;

      const headers = new Headers({
        "content-type": "text/html; charset=utf-8",
        "x-swift-rust-runtime": opts.runtime || "bun",
      });
      for (const [k, v] of Object.entries(opts.config?.headers || {})) headers.set(k, String(v));
      for (const c of setCookies) headers.append("set-cookie", c);
      return new Response(html, { headers });
    } catch (err) {
      const resp = thrownToResponse(err, url);
      if (resp) return resp;
      return new Response(`Internal Error: ${err?.message || err}`, { status: 500 });
    }
  };
}
